import{_ as a,o as i,c as l,ai as t}from"./chunks/framework.ampVZV4B.js";const m=JSON.parse('{"title":"英语口语","description":"","frontmatter":{},"headers":[],"relativePath":"english-speaking/index.md","filePath":"english-speaking/index.md"}'),s={name:"english-speaking/index.md"};function r(n,e,o,h,g,d){return i(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="英语口语" tabindex="-1">英语口语 <a class="header-anchor" href="#英语口语" aria-label="Permalink to “英语口语”">​</a></h1><blockquote><p>这个模块主要用于 <strong>英语口语学习、反复练习、场景表达积累</strong>。<br> 目标不是研究语法体系，而是：<strong>先敢开口，再说自然，再逐步熟练</strong>。</p></blockquote><hr><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to “模块定位”">​</a></h2><p>本模块主要做三件事：</p><ol><li><strong>打基础</strong>：先把 <code>48 音标</code> 和常见发音问题弄清楚</li><li><strong>背模板</strong>：按场景积累常用句型，减少“想说但说不出来”的卡顿</li><li><strong>做输出</strong>：围绕日常、工作、会议、电话、社交等场景，反复练习</li></ol><hr><h2 id="推荐学习顺序" tabindex="-1">推荐学习顺序 <a class="header-anchor" href="#推荐学习顺序" aria-label="Permalink to “推荐学习顺序”">​</a></h2><h3 id="第一步-先过一遍-48-音标" tabindex="-1">第一步：先过一遍 48 音标 <a class="header-anchor" href="#第一步-先过一遍-48-音标" aria-label="Permalink to “第一步：先过一遍 48 音标”">​</a></h3><ul><li><a href="/my-vitepress-site/english-speaking/phonetics-48.html">48 音标与发音入门</a></li></ul><h3 id="第二步-先看模板总览" tabindex="-1">第二步：先看模板总览 <a class="header-anchor" href="#第二步-先看模板总览" aria-label="Permalink to “第二步：先看模板总览”">​</a></h3><ul><li><a href="/my-vitepress-site/english-speaking/common-templates.html">通用沟通句型总览</a></li></ul><h3 id="第三步-按场景背句子" tabindex="-1">第三步：按场景背句子 <a class="header-anchor" href="#第三步-按场景背句子" aria-label="Permalink to “第三步：按场景背句子”">​</a></h3><ul><li><a href="/my-vitepress-site/english-speaking/templates-daily.html">日常通用口语模板</a></li><li><a href="/my-vitepress-site/english-speaking/templates-work.html">工作沟通口语模板</a></li><li><a href="/my-vitepress-site/english-speaking/templates-meeting.html">会议表达口语模板</a></li><li><a href="/my-vitepress-site/english-speaking/templates-call.html">电话/视频沟通模板</a></li><li><a href="/my-vitepress-site/english-speaking/templates-social.html">社交寒暄口语模板</a></li></ul><hr><h2 id="怎么使用这个模块" tabindex="-1">怎么使用这个模块 <a class="header-anchor" href="#怎么使用这个模块" aria-label="Permalink to “怎么使用这个模块”">​</a></h2><ul><li><strong>不要贪多</strong>：每天只记 10-20 句</li><li><strong>先照着读</strong>：先模仿，不急着自己造句</li><li><strong>场景化复习</strong>：比如今天只练“开会表达”，明天只练“日常寒暄”</li><li><strong>反复替换词汇</strong>：同一句模板，用不同人名、时间、地点替换</li></ul><hr><h2 id="学习原则" tabindex="-1">学习原则 <a class="header-anchor" href="#学习原则" aria-label="Permalink to “学习原则”">​</a></h2><ul><li>先追求 <strong>能说出来</strong></li><li>再追求 <strong>说得自然</strong></li><li>最后再追求 <strong>更地道、更丰富</strong></li></ul><blockquote><p>口语提升的关键不是一次背很多，而是<strong>高频重复 + 场景复现</strong>。</p></blockquote>',21)])])}const c=a(s,[["render",r]]);export{m as __pageData,c as default};
